mapper.select:
SELECT COUNT(1) FROM lab_notification
WHERE user_id = #{userId}
  AND type    = #{type, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
  AND is_read = 0
  AND ((related_biz_type IS NULL AND #{relatedBizType} IS NULL) OR related_biz_type = #{relatedBizType})
  AND ((related_biz_id   IS NULL AND #{relatedBizId}   IS NULL) OR related_biz_id   = #{relatedBizId})
